class ContentPipeline(dspy.ChainOfThought):
    generate_content: GenerateBrandContent = dspy.ChainOfModule()
    check_facts: FactCheckContent = dspy.ChainOfModule()

    def forward(self, topic: str, brand_guidelines: str):
        self.generate_content(topic=topic, brand_guidelines=brand_guidelines)
        self.check_facts(content=self.generate_content.content)
        return dspy.Prediction(
            content=self.generate_content.content,
            facts_ok=self.check_facts.facts_verified == 'yes'
        )

pipeline = ContentPipeline()
result = pipeline(topic='quantum computing', brand_guidelines='tech-forward, accessible')

